void clear_participants(struct sqlclntstate *clnt)
{
    struct participant *p = listc_rtl(&clnt->participants), *freep;
    while (p) {
        free(p->participant_name);
        free(p->participant_tier);
        freep = p;
        p = listc_rtl(&clnt->participants);
        free(freep);
    }
}

